#include <stdio.h>
int main() {
    int T, N, A[100000], count;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (A[i] * A[j] > A[i] + A[j]) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

